  "data": {
    "cards": [
      {
        "front": "What is a fever?",
        "back": "A fever is an increase in body temperature, often due to infection.",
        "icon": "thermometer"
      },
      {
        "front": "Common symptoms of fever?",
        "back": "• Elevated body temperature\n• Chills\n• Sweating\n• Headache",
        "icon": "symptoms"
      },
      {
        "front": "When to seek medical help?",
        "back": "• Persistent high fever\n• Severe headache\n• Rash\n• Difficulty breathing",
        "icon": "medical"
      },
      {
        "front": "How to measure fever?",
        "back": "• Use a digital thermometer\n• Measure orally, rectally, or underarm\n• Normal range: 97°F to 99°F",
        "icon": "measurement"
      }
    ]
  }
}
